import java.nio.file.Files;
import java.nio.file.InvalidPathException;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.StandardOpenOption;

public class FileService {

    private static final String BASE_DIRECTORY = "/tmp/upload";

    /**
     * Writes the provided content to the specified file path under /tmp/upload.
     *
     * @param filePath The file path provided by the user
     * @param content  The content to be written
     * @return true if the write operation was successful, false otherwise
     */
    public boolean writeFileContent(String filePath, String content) {
        // Validate input file path
        if (filePath == null || filePath.trim().isEmpty()) {
            return false;
        }

        // Handle null content gracefully by writing an empty string
        if (content == null) {
            content = "";
        }

        try {
            // Get the normalized absolute path of the base directory
            Path basePath = Paths.get(BASE_DIRECTORY).toAbsolutePath().normalize();

            // Resolve the user-provided file path against the base directory
            // If filePath is absolute, resolve() returns the absolute path itself.
            Path targetPath = basePath.resolve(filePath).toAbsolutePath().normalize();

            // Security check: Prevent Path Traversal (Directory Traversal)
            // Ensure the resolved target path is strictly inside the base directory
            if (!targetPath.startsWith(basePath)) {
                return false;
            }

            // Create parent directories if they do not exist
            Path parentDir = targetPath.getParent();
            if (parentDir != null && !Files.exists(parentDir)) {
                Files.createDirectories(parentDir);
            }

            // Write content to the file
            // CREATE: create a new file if it doesn't exist
            // TRUNCATE_EXISTING: overwrite the file if it already exists
            // WRITE: open for write access
            Files.write(
                targetPath, 
                content.getBytes(StandardCharsets.UTF_8), 
                StandardOpenOption.CREATE, 
                StandardOpenOption.TRUNCATE_EXISTING, 
                StandardOpenOption.WRITE
            );

            return true;

        } catch (IOException | InvalidPathException | SecurityException e) {
            // Catch file system exceptions, invalid paths, or permission issues
            // In a production environment, you might want to log the exception (e.g., log.error("...", e))
            return false;
        }
    }
}

